with open("../../data/kanji/kanji_grade6.json", "r", encoding="utf-8") as f:
    data = json.load(f)

added = 0
missing = []
for item in data:
    k = item["kanji"]
    if k in sentences_map:
        item["sentences"] = sentences_map[k]
        added += 1
    else:
        missing.append(k)

if missing:
    print(f"Missing kanji: {len(missing)} items")
    for m in missing:
        print(f"  - {repr(m)}")
else:
    print(f"All {added} kanji mapped successfully!")

with open("../../data/kanji/kanji_grade6.json", "w", encoding="utf-8") as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("Grade 6 sentences updated successfully!")
